      "category": "market",
      "severity": "medium",
      "evidence": "Transition risks associated with the global shift toward renewable energy sources may reduce long-term demand for our petroleum products"
    },
    {
      "factor": "Potential asset impairment from carbon pricing mechanisms or stricter emissions regulations",
      "category": "financial",
      "severity": "medium",
      "evidence": "potential asset impairment charges if carbon pricing mechanisms or stricter emissions regulations render certain reserves economically unviable"
    }
  ],
  "material_events": [
    {
      "event": "Hurricane Delphine damage to Gulf Coast refining facilities",
      "date": "2024-08",
      "impact": "negative",
      "details": "Caused production losses of approximately $340 million and triggered business interruption insurance claims"
    },
    {
